def now_ts() -> int:
    return int(time.time())

def safe_mkdir(p: str):
    os.makedirs(p, exist_ok=True)

def is_image_filename(name: str) -> bool:
    n = name.lower()
    return n.endswith(".jpg") or n.endswith(".jpeg") or n.endswith(".png") or n.endswith(".bmp") or n.endswith(".gif") or n.endswith(".webp")

def normalize_relpath(p: str) -> str:
    p = p.replace("\\", "/").lstrip("./")
    while p.startswith("/"):
        p = p[1:]
    if ".." in p.split("/"):
        raise ValueError("Invalid path traversal detected.")
    return p

def atomic_write_json(path: str, obj: dict):
    tmp = path + ".tmp." + uuid.uuid4().hex
    with open(tmp, "w", encoding="utf-8") as f:
        json.dump(obj, f, ensure_ascii=False, indent=2)
    os.replace(tmp, path)

class FileLock:
    def __init__(self, name: str, timeout_s: int = 600):
        self.path = os.path.join(LOCK_DIR, f"{name}.lock")
        self.timeout_s = timeout_s
        self.fd = None

    def __enter__(self):
        start = time.time()
        while True:
            try:
                self.fd = os.open(self.path, os.O_CREAT | os.O_EXCL | os.O_WRONLY)
                os.write(self.fd, str(os.getpid()).encode("utf-8"))
                return self
            except FileExistsError:
                if time.time() - start > self.timeout_s:
                    raise TimeoutError(f"Timeout waiting for lock: {self.path}")
                time.sleep(0.2)

    def __exit__(self, exc_type, exc, tb):
        try:
            if self.fd is not None:
                os.close(self.fd)
        finally:
            if os.path.exists(self.path):
                try:
                    os.remove(self.path)
                except OSError:
                    pass

