def save_upload_file(upload: UploadFile, dest_dir: str) -> Tuple[str, str]:
    safe_mkdir(dest_dir)
    upload_id = uuid.uuid4().hex
    fname = upload.filename or f"upload_{upload_id}"
    fname = os.path.basename(fname)
    stored = os.path.join(dest_dir, f"{upload_id}__{fname}")
    with open(stored, "wb") as f:
        shutil.copyfileobj(upload.file, f)
    return upload_id, stored

def record_upload(upload_id: str, kind: str, filename: str, stored_path: str, status: str = "stored", error: Optional[str] = None):
    con = db_connect()
    con.execute(
        "INSERT INTO uploads (id, created_at, kind, filename, stored_path, status, error) VALUES (?, ?, ?, ?, ?, ?, ?)",
        (upload_id, now_ts(), kind, filename, stored_path, status, error),
    )
    con.commit()
    con.close()

def update_upload_status(upload_id: str, status: str, error: Optional[str] = None):
    con = db_connect()
    con.execute("UPDATE uploads SET status=?, error=? WHERE id=?", (status, error, upload_id))
    con.commit()
    con.close()

def extract_zip_images(zip_path: str, dest_root: str) -> List[str]:
    safe_mkdir(dest_root)
    extracted_paths = []
    with zipfile.ZipFile(zip_path, "r") as z:
        for info in z.infolist():
            if info.is_dir():
                continue
            name = normalize_relpath(info.filename)
            if not is_image_filename(name):
                continue
            target = os.path.join(dest_root, uuid.uuid4().hex + "__" + os.path.basename(name))
            with z.open(info, "r") as src, open(target, "wb") as dst:
                shutil.copyfileobj(src, dst)
            extracted_paths.append(target)
    return extracted_paths

def parse_csv_examples(csv_path: str) -> pd.DataFrame:
    df = pd.read_csv(csv_path)
    cols = {c.lower(): c for c in df.columns}
    if "label" not in cols:
        raise ValueError("CSV must contain 'label' column.")
    if "image_path" not in cols and "image" not in cols and "path" not in cols:
        raise ValueError("CSV must contain 'image_path' (or 'image'/'path') column.")
    label_col = cols["label"]
    path_col = cols.get("image_path") or cols.get("image") or cols.get("path")
    contributor_col = cols.get("contributor")
    meta_col = cols.get("meta_json") or cols.get("meta") or cols.get("metadata")

    out = pd.DataFrame({
        "image_path": df[path_col].astype(str),
        "label": df[label_col].astype(str),
    })
    if contributor_col:
        out["contributor"] = df[contributor_col].astype(str)
    else:
        out["contributor"] = None
    if meta_col:
        out["meta_json"] = df[meta_col].astype(str)
    else:
        out["meta_json"] = None
    out = out.dropna(subset=["image_path", "label"])
    return out

def add_examples_from_csv(upload_id: str, csv_path: str, images_zip_path: Optional[str], images_base_dir: Optional[str], contributor: Optional[str]) -> Dict[str, int]:
    df = parse_csv_examples(csv_path)

    extracted_dir = None
    zip_extracted_map = {}

    if images_zip_path:
        extracted_dir = os.path.join(IMAGE_DIR, f"zip_{upload_id}")
        safe_mkdir(extracted_dir)
        extracted = extract_zip_images(images_zip_path, extracted_dir)
        for p in extracted:
            zip_extracted_map[os.path.basename(p).split("__", 1)[-1]] = p

    con = db_connect()
    cur = con.cursor()
    inserted = 0
    skipped = 0

    for _, row in df.iterrows():
        raw_path = str(row["image_path"])
        label = str(row["label"]).strip()
        if not label:
            skipped += 1
            continue

        stored_img_path = None

        rp = raw_path.strip()
        try:
            rp_norm = normalize_relpath(rp)
        except ValueError:
            skipped += 1
            continue

        if images_zip_path:
            base = os.path.basename(rp_norm)
            stored_img_path = zip_extracted_map.get(base)
            if stored_img_path is None:
                skipped += 1
                continue
        else:
            base_dir = images_base_dir or IMAGE_DIR
            candidate = os.path.join(base_dir, rp_norm)
            if not os.path.isfile(candidate):
                skipped += 1
                continue
            stored_img_path = os.path.abspath(candidate)

        ex_id = uuid.uuid4().hex
        meta_json = row.get("meta_json")
        ctb = contributor or row.get("contributor")
        try:
            cur.execute(
                "INSERT INTO examples (id, created_at, source_upload_id, image_path, label, contributor, meta_json) VALUES (?, ?, ?, ?, ?, ?, ?)",
                (ex_id, now_ts(), upload_id, stored_img_path, label, ctb, meta_json),
            )
            inserted += 1
        except sqlite3.IntegrityError:
            skipped += 1

    con.commit()
    con.close()

    return {"inserted": inserted, "skipped": skipped}

def add_single_example(image_path: str, label: str, contributor: Optional[str], meta_json: Optional[str], source_upload_id: Optional[str]) -> str:
    label = (label or "").strip()
    if not label:
        raise ValueError("Label is required.")
    if not os.path.isfile(image_path):
        raise ValueError("Image file does not exist.")
    ex_id = uuid.uuid4().hex
    con = db_connect()
    con.execute(
        "INSERT INTO examples (id, created_at, source_upload_id, image_path, label, contributor, meta_json) VALUES (?, ?, ?, ?, ?, ?, ?)",
        (ex_id, now_ts(), source_upload_id, os.path.abspath(image_path), label, contributor, meta_json),
    )
    con.commit()
    con.close()
    return ex_id

