def load_examples_df(limit: Optional[int] = None) -> pd.DataFrame:
    con = db_connect()
    q = "SELECT id, image_path, label FROM examples"
    if limit is not None:
        q += " LIMIT ?"
        rows = con.execute(q, (int(limit),)).fetchall()
