def build_model(num_classes: int, image_size: Tuple[int, int]) -> tf.keras.Model:
    base = tf.keras.applications.MobileNetV2(
        input_shape=(image_size[0], image_size[1], 3),
        include_top=False,
        weights="imagenet",
        pooling="avg",
    )
    base.trainable = False

    inputs = tf.keras.Input(shape=(image_size[0], image_size[1], 3))
    x = tf.keras.applications.mobilenet_v2.preprocess_input(inputs)
    x = base(x, training=False)
    x = tf.keras.layers.Dropout(0.2)(x)
    outputs = tf.keras.layers.Dense(num_classes, activation="softmax")(x)
    model = tf.keras.Model(inputs, outputs)
    model.compile(
        optimizer=tf.keras.optimizers.Adam(learning_rate=1e-3),
        loss="sparse_categorical_crossentropy",
        metrics=["accuracy"],
    )
    return model

def make_dataset(df: pd.DataFrame, label_to_index: Dict[str, int], image_size: Tuple[int, int], batch_size: int, shuffle: bool) -> tf.data.Dataset:
    paths = df["image_path"].astype(str).tolist()
    labels = [label_to_index[l] for l in df["label"].astype(str).tolist()]

    ds = tf.data.Dataset.from_tensor_slices((paths, labels))

    def _load(path, y):
        img_bytes = tf.io.read_file(path)
        img = tf.image.decode_image(img_bytes, channels=3, expand_animations=False)
        img = tf.image.convert_image_dtype(img, tf.float32)
        img = tf.image.resize(img, image_size, method="bilinear")
        return img, y

    ds = ds.map(_load, num_parallel_calls=tf.data.AUTOTUNE)
    if shuffle:
        ds = ds.shuffle(buffer_size=min(2000, len(paths)), reshuffle_each_iteration=True)
    ds = ds.batch(batch_size).prefetch(tf.data.AUTOTUNE)
    return ds

def split_df(df: pd.DataFrame, validation_split: float, seed: int = 42) -> Tuple[pd.DataFrame, pd.DataFrame]:
    if len(df) < 2:
        return df, df.iloc[0:0]
    df = df.sample(frac=1.0, random_state=seed).reset_index(drop=True)
    n_val = int(round(len(df) * validation_split))
    n_val = max(1, n_val) if len(df) >= 5 else max(0, n_val)
    val_df = df.iloc[:n_val]
    train_df = df.iloc[n_val:]
    if len(train_df) == 0:
        train_df = val_df
    return train_df, val_df

def export_saved_model(model: tf.keras.Model, export_path: str, labels: List[str], meta: dict):
    safe_mkdir(export_path)
    model.save(export_path)
    atomic_write_json(os.path.join(export_path, "labels.json"), {"labels": labels})
    atomic_write_json(os.path.join(export_path, "meta.json"), meta)

def register_model(version: str, model_path: str, labels: List[str], meta: dict):
    con = db_connect()
    con.execute(
        "INSERT INTO model_registry (created_at, version, status, model_path, labels_json, meta_json) VALUES (?, ?, ?, ?, ?, ?)",
        (now_ts(), version, "active", model_path, json.dumps({"labels": labels}), json.dumps(meta)),
    )
    con.commit()
    con.close()

def get_active_model() -> Optional[dict]:
    con = db_connect()
    row = con.execute(
        "SELECT version, model_path, labels_json, meta_json, created_at FROM model_registry WHERE status='active' ORDER BY created_at DESC LIMIT 1"
    ).fetchone()
    con.close()
    if not row:
        return None
    labels = json.loads(row["labels_json"]).get("labels", [])
    meta = json.loads(row["meta_json"]) if row["meta_json"] else {}
    return {
        "version": row["version"],
        "model_path": row["model_path"],
        "labels": labels,
        "meta": meta,
        "created_at": row["created_at"],
    }

def set_all_models_inactive():
    con = db_connect()
    con.execute("UPDATE model_registry SET status='inactive' WHERE status='active'")
    con.commit()
    con.close()

