TRAINING_STATE = {
    "running": False,
    "current_run_id": None,
    "last_run_id": None,
}

def record_training_run(run_id: str, status: str, params: dict, metrics: Optional[dict] = None, error: Optional[str] = None, model_version: Optional[str] = None, model_path: Optional[str] = None):
    con = db_connect()
    con.execute(
        "INSERT INTO training_runs (id, created_at, status, params_json, metrics_json, error, model_version, model_path) VALUES (?, ?, ?, ?, ?, ?, ?, ?)",
        (run_id, now_ts(), status, json.dumps(params), json.dumps(metrics) if metrics else None, error, model_version, model_path),
    )
    con.commit()
    con.close()

def update_training_run(run_id: str, status: str, metrics: Optional[dict] = None, error: Optional[str] = None, model_version: Optional[str] = None, model_path: Optional[str] = None):
    con = db_connect()
    con.execute(
        "UPDATE training_runs SET status=?, metrics_json=?, error=?, model_version=?, model_path=? WHERE id=?",
        (status, json.dumps(metrics) if metrics else None, error, model_version, model_path, run_id),
    )
    con.commit()
    con.close()

def get_training_run(run_id: str) -> Optional[dict]:
    con = db_connect()
    row = con.execute("SELECT * FROM training_runs WHERE id=?", (run_id,)).fetchone()
    con.close()
    if not row:
        return None
    return {
        "id": row["id"],
        "created_at": row["created_at"],
        "status": row["status"],
        "params": json.loads(row["params_json"]),
        "metrics": json.loads(row["metrics_json"]) if row["metrics_json"] else None,
        "error": row["error"],
        "model_version": row["model_version"],
        "model_path": row["model_path"],
    }

def train_job(run_id: str, params: dict):
    with FileLock("training", timeout_s=3600):
        TRAINING_STATE["running"] = True
        TRAINING_STATE["current_run_id"] = run_id
        try:
            df = load_examples_df(limit=params.get("limit"))
            if df.empty:
                raise RuntimeError("No training examples available.")

            labels = sorted(df["label"].unique().tolist())
            if len(labels) < 2:
                raise RuntimeError("Need at least 2 distinct labels to train a classifier.")

            label_to_index = {l: i for i, l in enumerate(labels)}

            image_size = tuple(params.get("image_size", DEFAULT_IMAGE_SIZE))
            batch_size = int(params.get("batch_size", DEFAULT_BATCH_SIZE))
            epochs = int(params.get("epochs", DEFAULT_EPOCHS))
            validation_split = float(params.get("validation_split", DEFAULT_VALIDATION_SPLIT))
            seed = int(params.get("seed", 42))

            train_df, val_df = split_df(df, validation_split=validation_split, seed=seed)

            train_ds = make_dataset(train_df, label_to_index, image_size, batch_size, shuffle=True)
            val_ds = make_dataset(val_df, label_to_index, image_size, batch_size, shuffle=False) if len(val_df) else None

            model = build_model(num_classes=len(labels), image_size=image_size)

            callbacks = [
                tf.keras.callbacks.EarlyStopping(monitor="val_accuracy", patience=2, restore_best_weights=True) if val_ds is not None else tf.keras.callbacks.EarlyStopping(monitor="accuracy", patience=2, restore_best_weights=True),
            ]

            history = model.fit(
                train_ds,
                validation_data=val_ds,
                epochs=epochs,
                callbacks=callbacks,
                verbose=0,
            )

            metrics = {
                "history": {k: [float(x) for x in v] for k, v in history.history.items()},
                "num_examples": int(len(df)),
                "num_train": int(len(train_df)),
                "num_val": int(len(val_df)),
                "labels": labels,
            }

            version = f"v{now_ts()}_{run_id[:8]}"
            export_path = os.path.join(EXPORT_DIR, version)

            meta = {
                "version": version,
                "created_at": now_ts(),
                "params": {
                    "image_size": list(image_size),
                    "batch_size": batch_size,
                    "epochs": epochs,
                    "validation_split": validation_split,
                    "seed": seed,
                },
                "data": {
                    "num_examples": int(len(df)),
                    "labels": labels,
                },
            }

            export_saved_model(model, export_path, labels, meta)

            set_all_models_inactive()
            register_model(version, export_path, labels, meta)

            update_training_run(run_id, status="completed", metrics=metrics, model_version=version, model_path=export_path)
            TRAINING_STATE["last_run_id"] = run_id

        except Exception as e:
            update_training_run(run_id, status="failed", error=str(e))
        finally:
            TRAINING_STATE["running"] = False
            TRAINING_STATE["current_run_id"] = None

def start_training_async(params: dict) -> str:
    if TRAINING_STATE["running"]:
        raise RuntimeError("Training is already running.")
    run_id = uuid.uuid4().hex
    record_training_run(run_id, status="running", params=params)
    t = threading.Thread(target=train_job, args=(run_id, params), daemon=True)
    t.start()
    return run_id

