_MODEL_CACHE = {
    "version": None,
    "model": None,
    "labels": None,
}

def load_active_model_cached():
    active = get_active_model()
    if not active:
        return None
    if _MODEL_CACHE["version"] == active["version"] and _MODEL_CACHE["model"] is not None:
        return _MODEL_CACHE["model"], _MODEL_CACHE["labels"], active
    model = tf.keras.models.load_model(active["model_path"])
    _MODEL_CACHE["version"] = active["version"]
    _MODEL_CACHE["model"] = model
    _MODEL_CACHE["labels"] = active["labels"]
    return model, active["labels"], active

def preprocess_image_bytes(image_bytes: bytes, image_size: Tuple[int, int]) -> np.ndarray:
    img = tf.io.decode_image(image_bytes, channels=3, expand_animations=False)
    img = tf.image.convert_image_dtype(img, tf.float32)
    img = tf.image.resize(img, image_size, method="bilinear")
    return img.numpy()

