app = FastAPI(title="Community Training Pipeline", version="1.0.0")

class TrainRequest(BaseModel):
    epochs: int = DEFAULT_EPOCHS
    batch_size: int = DEFAULT_BATCH_SIZE
    validation_split: float = DEFAULT_VALIDATION_SPLIT
    image_size: List[int] = [DEFAULT_IMAGE_SIZE[0], DEFAULT_IMAGE_SIZE[1]]
    seed: int = 42
    limit: Optional[int] = None

@app.get("/health")
def health():
    return {"ok": True, "time": now_ts()}

@app.get("/stats")
def stats():
    active = get_active_model()
    return {
        "num_examples": count_examples(),
        "labels": get_all_labels(),
        "active_model": active,
        "training": TRAINING_STATE,
    }

@app.post("/upload/csv")
async def upload_csv(
    csv_file: UploadFile = File(...),
    images_zip: Optional[UploadFile] = File(None),
    images_base_dir: Optional[str] = Form(None),
    contributor: Optional[str] = Form(None),
):
    if not (csv_file.filename or "").lower().endswith(".csv"):
        raise HTTPException(status_code=400, detail="csv_file must be a .csv")

    upload_id, csv_path = save_upload_file(csv_file, UPLOAD_DIR)
    record_upload(upload_id, kind="csv", filename=csv_file.filename or "data.csv", stored_path=csv_path, status="stored")

    zip_path = None
    if images_zip is not None:
        if not (images_zip.filename or "").lower().endswith(".zip"):
            update_upload_status(upload_id, "failed", "images_zip must be a .zip")
            raise HTTPException(status_code=400, detail="images_zip must be a .zip")
        _, zip_path = save_upload_file(images_zip, UPLOAD_DIR)

    try:
        update_upload_status(upload_id, "processing", None)
        res = add_examples_from_csv(
            upload_id=upload_id,
            csv_path=csv_path,
            images_zip_path=zip_path,
            images_base_dir=images_base_dir,
            contributor=contributor,
        )
        update_upload_status(upload_id, "completed", None)
        return {"upload_id": upload_id, **res}
    except Exception as e:
        update_upload_status(upload_id, "failed", str(e))
        raise HTTPException(status_code=400, detail=str(e))

